import { prisma } from "./prisma";

export type RetrievedArticle = {
  id: string;
  code: string;
  chapter: string;
  articleNumber: string;
  language: string;
  text: string;
  source: string;
  updatedAt: Date;
};

const cosineSimilarity = (a: number[], b: number[]) => {
  if (a.length !== b.length || a.length === 0) {
    return 0;
  }

  let dot = 0;
  let normA = 0;
  let normB = 0;

  for (let i = 0; i < a.length; i += 1) {
    dot += a[i] * b[i];
    normA += a[i] * a[i];
    normB += b[i] * b[i];
  }

  if (normA === 0 || normB === 0) {
    return 0;
  }

  return dot / (Math.sqrt(normA) * Math.sqrt(normB));
};

export const retrieveRelevantArticles = async (embedding: number[], limit = 4) => {
  if (!embedding.length) {
    return [] as RetrievedArticle[];
  }

  const stored = await prisma.lawEmbedding.findMany({
    include: {
      article: true
    }
  });

  const scored = stored
    .map((item) => ({
      score: cosineSimilarity(embedding, item.embedding),
      article: item.article
    }))
    .filter((item) => item.score > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, limit)
    .map(({ article }) => ({
      id: article.id,
      code: article.code,
      chapter: article.chapter,
      articleNumber: article.articleNumber,
      language: article.language,
      text: article.text,
      source: article.source,
      updatedAt: article.updatedAt
    }));

  return scored;
};

export const keywordFallback = async (question: string, limit = 4) => {
  const results = await prisma.lawArticle.findMany({
    where: {
      text: {
        contains: question,
        mode: "insensitive"
      }
    },
    orderBy: {
      updatedAt: "desc"
    },
    take: limit
  });

  return results.map((article) => ({
    id: article.id,
    code: article.code,
    chapter: article.chapter,
    articleNumber: article.articleNumber,
    language: article.language,
    text: article.text,
    source: article.source,
    updatedAt: article.updatedAt
  }));
};
