import { NextResponse } from "next/server";
import { headers } from "next/headers";
import { chatRequestSchema } from "../../../lib/validators";
import { createEmbedding } from "../../../lib/embeddings";
import { keywordFallback, retrieveRelevantArticles } from "../../../lib/search";
import { generateResponse } from "../../../lib/openai";
import { prisma } from "../../../lib/prisma";
import { checkRateLimit } from "../../../lib/rateLimit";

export const POST = async (request: Request) => {
  const body = await request.json();
  const parsed = chatRequestSchema.safeParse(body);

  if (!parsed.success) {
    return NextResponse.json({ error: "Invalid request" }, { status: 400 });
  }

  const ip = headers().get("x-forwarded-for")?.split(",")[0]?.trim() || "unknown";
  const allowed = await checkRateLimit(ip);
  if (!allowed) {
    return NextResponse.json({ error: "Rate limit exceeded" }, { status: 429 });
  }

  const { question, context } = parsed.data;
  const embedding = await createEmbedding(question);
  let articles = await retrieveRelevantArticles(embedding);

  if (articles.length === 0) {
    articles = await keywordFallback(question);
  }

  if (articles.length === 0) {
    const declined =
      "I cannot answer reliably because I could not find relevant law articles. " +
      "Please consult a licensed lawyer.";

    const query = await prisma.chatQuery.create({
      data: {
        question,
        answer: declined,
        grounded: false,
        ip,
        userAgent: headers().get("user-agent") || undefined
      }
    });

    return NextResponse.json({
      answer: declined,
      citations: [],
      grounded: false,
      queryId: query.id
    });
  }

  const lawContext = articles
    .map(
      (article, index) =>
        `(${index + 1}) ${article.code} Article ${article.articleNumber} [${article.language}]\n${article.text}`
    )
    .join("\n\n");

  const systemPrompt =
    "You are AI-Mizan, a Moroccan legal guidance assistant. " +
    "Always answer with: legal explanation, relevant articles, practical next steps, and when to consult a lawyer. " +
    "If you do not have enough context, say so clearly. " +
    "Cite articles using their code and article number.";

  const userPrompt =
    `Question: ${question}\n\n` +
    (context ? `Context: ${context}\n\n` : "") +
    `Relevant law articles:\n${lawContext}`;

  try {
    const answer = await generateResponse([
      { role: "system", content: systemPrompt },
      { role: "user", content: userPrompt }
    ]);

    const query = await prisma.chatQuery.create({
      data: {
        question,
        answer,
        grounded: true,
        ip,
        userAgent: headers().get("user-agent") || undefined
      }
    });

    await prisma.chatCitation.createMany({
      data: articles.map((article) => ({
        chatQueryId: query.id,
        articleId: article.id,
        code: article.code,
        articleNumber: article.articleNumber
      }))
    });

    return NextResponse.json({
      answer,
      citations: articles.map((article) => ({
        code: article.code,
        articleNumber: article.articleNumber
      })),
      grounded: true,
      queryId: query.id
    });
  } catch (error) {
    return NextResponse.json(
      { error: "Failed to generate response" },
      { status: 500 }
    );
  }
};
